143	/**
144	 * Find all packing patterns in architecture
145	 * [0..num_packing_patterns-1]
146	 *
147	 * Limitations: Currently assumes that forced pack nets must be single-fanout
148	 * as this covers all the reasonable architectures we wanted.
149	 * More complicated structures should probably be handled either downstream
150	 * (general packing) or upstream (in tech mapping).
151	 * If this limitation is too constraining, code is designed so that this limitation can be removed.
152	 */
153	static std::vector<t_pack_patterns> alloc_and_load_pack_patterns(const std::vector<t_logical_block_type>& logical_block_types) {
154	    int L_num_blocks;
155	    t_pb_graph_edge* expansion_edge;
156	
157	    // Use this map to keep track of the last primitive from each pb_graph_node
158	    // that was added to a packing pattern.
159	    std::unordered_map<t_pb_graph_node*, t_pack_pattern_block*> last_added_pattern_block;
160	
161	    /* alloc and initialize array of packing patterns based on architecture complex blocks */
162	    std::unordered_map<std::string, int> pattern_names;
163	    for (const t_logical_block_type& type : logical_block_types) {
164	        discover_pattern_names_in_pb_graph_node(type.pb_graph_head, pattern_names, last_added_pattern_block);
165	    }
166	
167	    std::vector<t_pack_patterns> packing_patterns = alloc_and_init_pattern_list_from_hash(pattern_names);
168	
169	    /* load packing patterns by traversing the edges to find edges belonging to pattern */
170	    for (size_t i = 0; i < pattern_names.size(); i++) {
171	        for (const t_logical_block_type& type : logical_block_types) {
172	            // find an edge that belongs to this pattern
173	            expansion_edge = find_expansion_edge_of_pattern(i, type.pb_graph_head);
174	            if (!expansion_edge) {
175	                continue;
176	            }
177	
178	            L_num_blocks = 0;
179	            packing_patterns[i].base_cost = 0;
180	            // use the found expansion edge to build the pack pattern
181	            backward_expand_pack_pattern_from_edge(expansion_edge,
182	                                                   packing_patterns[i], nullptr, nullptr, &L_num_blocks,
183	                                                   last_added_pattern_block);
184	            packing_patterns[i].num_blocks = L_num_blocks;
185	
186	            /* Default settings: A section of a netlist must match all blocks in a pack
187	             * pattern before it can be made a molecule except for carry-chains.
188	             * For carry-chains, since carry-chains are typically quite flexible in terms
189	             * of size, it is optional whether or not an atom in a netlist matches any
190	             * particular block inside the chain */
191	            packing_patterns[i].is_block_optional = new bool[L_num_blocks];
192	            for (int k = 0; k < L_num_blocks; k++) {
193	                packing_patterns[i].is_block_optional[k] = false;
194	                if (packing_patterns[i].is_chain && packing_patterns[i].root_block->block_id != k) {
195	                    packing_patterns[i].is_block_optional[k] = true;
196	                }
197	            }
198	
199	            // if this is a chain pattern (extends between complex blocks), check if there
200	            // are multiple equivalent chains with different starting and ending points
201	            if (packing_patterns[i].is_chain) {
202	                find_all_equivalent_chains(&packing_patterns[i], type.pb_graph_head);
203	                print_chain_starting_points(&packing_patterns[i]);
204	            }
205	
206	            // if pack pattern i is found to belong to current block type, go to next pack pattern
207	            break;
208	        }
209	    }
210	
211	    //Sanity check, every pattern should have a root block
212	    for (size_t i = 0; i < pattern_names.size(); ++i) {
213	        if (packing_patterns[i].root_block == nullptr) {
214	            VPR_FATAL_ERROR(VPR_ERROR_ARCH, "Failed to find root block for pack pattern %s", packing_patterns[i].name);
215	        }
216	    }
217	
218	    return packing_patterns;
219	}
