221	/**
222	 * Locate all pattern names
223	 *				For cases where a pattern inference is "obvious", mark it as obvious.
224	 */
225	static void discover_pattern_names_in_pb_graph_node(t_pb_graph_node* pb_graph_node,
226	                                                    std::unordered_map<std::string, int>& pattern_names,
227	                                                    std::unordered_map<t_pb_graph_node*, t_pack_pattern_block*>& last_added_pattern_block) {
228	    /* Iterate over all edges to discover if an edge in current physical block belongs to a pattern
229	     * If edge does, then record the name of the pattern in a hash table */
230	
231	    if (pb_graph_node == nullptr) {
232	        return;
233	    }
234	
235	    last_added_pattern_block[pb_graph_node] = nullptr;
236	
237	    for (int i = 0; i < pb_graph_node->num_input_ports; i++) {
238	        for (int j = 0; j < pb_graph_node->num_input_pins[i]; j++) {
239	            bool hasPattern = false;
240	            for (int k = 0; k < pb_graph_node->input_pins[i][j].num_output_edges; k++) {
241	                auto output_edge = pb_graph_node->input_pins[i][j].output_edges[k];
242	                for (int m = 0; m < output_edge->num_pack_patterns; m++) {
243	                    hasPattern = true;
244	                    // insert the found pattern name to the hash table. If this pattern is inserted
245	                    // for the first time, then its index is the current size of the hash table
246	                    // otherwise the insert function will return an iterator of the previously
247	                    // inserted element with the index given to that pattern
248	                    std::string pattern_name(output_edge->pack_pattern_names[m]);
249	                    int index = (pattern_names.insert({pattern_name, pattern_names.size()}).first)->second;
250	                    if (!output_edge->pack_pattern_indices) {
251	                        output_edge->pack_pattern_indices = new int[output_edge->num_pack_patterns];
252	                    }
253	                    output_edge->pack_pattern_indices[m] = index;
254	                    // if this output edges belongs to a pack pattern. Expand forward starting from
255	                    // all its output pins to check if you need to infer pattern for direct connections
256	                    for (int ipin = 0; ipin < output_edge->num_output_pins; ipin++) {
257	                        forward_infer_pattern(output_edge->output_pins[ipin]);
258	                    }
259	                }
260	            }
261	            // if the output edge to this pin is annotated with a pack pattern
262	            // trace the inputs to this pin and mark them to infer pattern
263	            // if they are direct connections (num_input_edges == 1)
264	            if (hasPattern) {
265	                backward_infer_pattern(&pb_graph_node->input_pins[i][j]);
266	            }
267	        }
268	    }
269	
270	    for (int i = 0; i < pb_graph_node->num_output_ports; i++) {
271	        for (int j = 0; j < pb_graph_node->num_output_pins[i]; j++) {
272	            bool hasPattern = false;
273	            for (int k = 0; k < pb_graph_node->output_pins[i][j].num_output_edges; k++) {
274	                auto output_edge = pb_graph_node->output_pins[i][j].output_edges[k];
275	                for (int m = 0; m < output_edge->num_pack_patterns; m++) {
276	                    hasPattern = true;
277	                    // insert the found pattern name to the hash table. If this pattern is inserted
278	                    // for the first time, then its index is the current size of the hash table
279	                    // otherwise the insert function will return an iterator of the previously
280	                    // inserted element with the index given to that pattern
281	                    std::string pattern_name(output_edge->pack_pattern_names[m]);
282	                    int index = (pattern_names.insert({pattern_name, pattern_names.size()}).first)->second;
283	                    if (!output_edge->pack_pattern_indices) {
284	                        output_edge->pack_pattern_indices = new int[output_edge->num_pack_patterns];
285	                    }
286	                    output_edge->pack_pattern_indices[m] = index;
287	                    // if this output edges belongs to a pack pattern. Expand forward starting from
288	                    // all its output pins to check if you need to infer pattern for direct connections
289	                    for (int ipin = 0; ipin < output_edge->num_output_pins; ipin++) {
290	                        forward_infer_pattern(output_edge->output_pins[ipin]);
291	                    }
292	                }
293	            }
294	            // if the output edge to this pin is annotated with a pack pattern
295	            // trace the inputs to this pin and mark them to infer pattern
296	            // if they are direct connections (num_input_edges == 1)
297	            if (hasPattern) {
298	                backward_infer_pattern(&pb_graph_node->output_pins[i][j]);
299	            }
300	        }
301	    }
302	
303	    for (int i = 0; i < pb_graph_node->num_clock_ports; i++) {
304	        for (int j = 0; j < pb_graph_node->num_clock_pins[i]; j++) {
305	            bool hasPattern = false;
306	            for (int k = 0; k < pb_graph_node->clock_pins[i][j].num_output_edges; k++) {
307	                auto& output_edge = pb_graph_node->clock_pins[i][j].output_edges[k];
308	                for (int m = 0; m < output_edge->num_pack_patterns; m++) {
309	                    hasPattern = true;
310	                    // insert the found pattern name to the hash table. If this pattern is inserted
311	                    // for the first time, then its index is the current size of the hash table
312	                    // otherwise the insert function will return an iterator of the previously
313	                    // inserted element with the index given to that pattern
314	                    std::string pattern_name(output_edge->pack_pattern_names[m]);
315	                    int index = (pattern_names.insert({pattern_name, pattern_names.size()}).first)->second;
316	                    if (output_edge->pack_pattern_indices == nullptr) {
317	                        output_edge->pack_pattern_indices = new int[output_edge->num_pack_patterns];
318	                    }
319	                    output_edge->pack_pattern_indices[m] = index;
320	                    // if this output edges belongs to a pack pattern. Expand forward starting from
321	                    // all its output pins to check if you need to infer pattern for direct connections
322	                    for (int ipin = 0; ipin < output_edge->num_output_pins; ipin++) {
323	                        forward_infer_pattern(output_edge->output_pins[ipin]);
324	                    }
325	                }
326	            }
327	            // if the output edge to this pin is annotated with a pack pattern
328	            // trace the inputs to this pin and mark them to infer pattern
329	            // if they are direct connections (num_input_edges == 1)
330	            if (hasPattern) {
331	                backward_infer_pattern(&pb_graph_node->clock_pins[i][j]);
332	            }
333	        }
334	    }
335	
336	    for (int i = 0; i < pb_graph_node->pb_type->num_modes; i++) {
337	        for (int j = 0; j < pb_graph_node->pb_type->modes[i].num_pb_type_children; j++) {
338	            for (int k = 0; k < pb_graph_node->pb_type->modes[i].pb_type_children[j].num_pb; k++) {
339	                discover_pattern_names_in_pb_graph_node(&pb_graph_node->child_pb_graph_nodes[i][j][k], pattern_names, last_added_pattern_block);
340	            }
341	        }
342	    }
343	}
