345	/**
346	 * In obvious cases where a pattern edge has only one path to go, set that path to be inferred
347	 */
348	static void forward_infer_pattern(t_pb_graph_pin* pb_graph_pin) {
349	    if (pb_graph_pin->num_output_edges == 1 && pb_graph_pin->output_edges[0]->num_pack_patterns == 0 && pb_graph_pin->output_edges[0]->infer_pattern == false) {
350	        pb_graph_pin->output_edges[0]->infer_pattern = true;
351	        if (pb_graph_pin->output_edges[0]->num_output_pins == 1) {
352	            forward_infer_pattern(pb_graph_pin->output_edges[0]->output_pins[0]);
353	        }
354	    }
355	}
356	static void backward_infer_pattern(t_pb_graph_pin* pb_graph_pin) {
357	    if (pb_graph_pin->num_input_edges == 1 && pb_graph_pin->input_edges[0]->num_pack_patterns == 0 && pb_graph_pin->input_edges[0]->infer_pattern == false) {
358	        pb_graph_pin->input_edges[0]->infer_pattern = true;
359	        if (pb_graph_pin->input_edges[0]->num_input_pins == 1) {
360	            backward_infer_pattern(pb_graph_pin->input_edges[0]->input_pins[0]);
361	        }
362	    }
363	}
