365	/**
366	 * Allocates memory for models and loads the name of the packing pattern
367	 * so that it can be identified and loaded with more complete information later
368	 */
369	static std::vector<t_pack_patterns> alloc_and_init_pattern_list_from_hash(const std::unordered_map<std::string, int>& pattern_names) {
370	    std::vector<t_pack_patterns> nlist(pattern_names.size());
371	
372	    for (const auto& curr_pattern : pattern_names) {
373	        VTR_ASSERT(nlist[curr_pattern.second].name == nullptr);
374	        nlist[curr_pattern.second].name = vtr::strdup(curr_pattern.first.c_str());
375	        nlist[curr_pattern.second].root_block = nullptr;
376	        nlist[curr_pattern.second].is_chain = false;
377	        nlist[curr_pattern.second].index = curr_pattern.second;
378	    }
379	
380	    return nlist;
381	}
