389	static void free_pack_pattern(t_pack_patterns* pack_pattern) {
390	    if (pack_pattern) {
391	        int num_pack_pattern_blocks = pack_pattern->num_blocks;
392	        t_pack_pattern_block** pattern_block_list = new t_pack_pattern_block*[num_pack_pattern_blocks];
393	        for (int i = 0; i < num_pack_pattern_blocks; i++)
394	            pattern_block_list[i] = nullptr;
395	
396	        free(pack_pattern->name);
397	        delete[] pack_pattern->is_block_optional;
398	        free_pack_pattern_block(pack_pattern->root_block, pattern_block_list);
399	        for (int j = 0; j < num_pack_pattern_blocks; j++) {
400	            delete pattern_block_list[j];
401	        }
402	        delete[] pattern_block_list;
403	    }
404	}
