406	/**
407	 * Locate first edge that belongs to pattern index
408	 */
409	static t_pb_graph_edge* find_expansion_edge_of_pattern(const int pattern_index,
410	                                                       const t_pb_graph_node* pb_graph_node) {
411	    int i, j, k, m;
412	    t_pb_graph_edge* edge;
413	    /* Iterate over all edges to discover if an edge in current physical block belongs to a pattern
414	     * If edge does, then return that edge
415	     */
416	
417	    if (pb_graph_node == nullptr) {
418	        return nullptr;
419	    }
420	
421	    for (i = 0; i < pb_graph_node->num_input_ports; i++) {
422	        for (j = 0; j < pb_graph_node->num_input_pins[i]; j++) {
423	            auto& input_pin = pb_graph_node->input_pins[i][j];
424	            for (k = 0; k < input_pin.num_output_edges; k++) {
425	                for (m = 0; m < input_pin.output_edges[k]->num_pack_patterns; m++) {
426	                    if (input_pin.output_edges[k]->pack_pattern_indices[m] == pattern_index) {
427	                        return input_pin.output_edges[k];
428	                    }
429	                }
430	            }
431	        }
432	    }
433	
434	    for (i = 0; i < pb_graph_node->num_output_ports; i++) {
435	        for (j = 0; j < pb_graph_node->num_output_pins[i]; j++) {
436	            auto& output_pin = pb_graph_node->output_pins[i][j];
437	            for (k = 0; k < output_pin.num_output_edges; k++) {
438	                for (m = 0; m < output_pin.output_edges[k]->num_pack_patterns; m++) {
439	                    if (output_pin.output_edges[k]->pack_pattern_indices[m] == pattern_index) {
440	                        return output_pin.output_edges[k];
441	                    }
442	                }
443	            }
444	        }
445	    }
446	
447	    for (i = 0; i < pb_graph_node->num_clock_ports; i++) {
448	        for (j = 0; j < pb_graph_node->num_clock_pins[i]; j++) {
449	            auto& clock_pin = pb_graph_node->clock_pins[i][j];
450	            for (k = 0; k < clock_pin.num_output_edges; k++) {
451	                for (m = 0; m < clock_pin.output_edges[k]->num_pack_patterns; m++) {
452	                    if (clock_pin.output_edges[k]->pack_pattern_indices[m] == pattern_index) {
453	                        return clock_pin.output_edges[k];
454	                    }
455	                }
456	            }
457	        }
458	    }
459	
460	    for (i = 0; i < pb_graph_node->pb_type->num_modes; i++) {
461	        auto& pb_mode = pb_graph_node->pb_type->modes[i];
462	        for (j = 0; j < pb_mode.num_pb_type_children; j++) {
463	            for (k = 0; k < pb_mode.pb_type_children[j].num_pb; k++) {
464	                edge = find_expansion_edge_of_pattern(pattern_index, &pb_graph_node->child_pb_graph_nodes[i][j][k]);
465	                if (edge != nullptr) {
466	                    return edge;
467	                }
468	            }
469	        }
470	    }
471	    return nullptr;
472	}
