474	/**
475	 *  This function expands forward from the given expansion_edge. If a primitive is found that
476	 *  belongs to the pack pattern we are searching for, create a pack pattern block of using
477	 *  this primitive to be added later to the pack pattern when creating the pack pattern
478	 *  connections in the backward_expand_pack_pattern_from_edge function.
479	 *
480	 *  expansion_edge: starting edge to expand forward from
481	 *  list_of_packing_patterns: list of packing patterns in the architecture
482	 *  curr_pattern_index: current packing pattern that we are building
483	 *  L_num_blocks: number of primitives found to belong to this pattern so far
484	 *  make_root_of_chain: flag indicating that the given expansion_edge is connected
485	 *                      to a primitive that is the root of this packing pattern
486	 *
487	 *  Convention: Pack pattern block connections are made on backward expansion only (to make
488	 *              future multi-fanout support easier) so this function will not update connections
489	 */
490	static void forward_expand_pack_pattern_from_edge(const t_pb_graph_edge* expansion_edge,
491	                                                  t_pack_patterns& packing_pattern,
492	                                                  int* L_num_blocks,
493	                                                  bool make_root_of_chain,
494	                                                  std::unordered_map<t_pb_graph_node*, t_pack_pattern_block*>& last_added_pattern_block) {
495	    int i, j, k;
496	    int iport, ipin, iedge;
497	    bool found; /* Error checking, ensure only one fan-out for each pattern net */
498	    t_pack_pattern_block* destination_block = nullptr;
499	    t_pb_graph_node* destination_pb_graph_node = nullptr;
500	    int curr_pattern_index = packing_pattern.index;
501	
502	    found = expansion_edge->infer_pattern;
503	    // if the pack pattern shouldn't be inferred check if the expansion
504	    // edge is annotated with the current pack pattern we are expanding
505	    for (i = 0; !found && i < expansion_edge->num_pack_patterns; i++) {
506	        if (expansion_edge->pack_pattern_indices[i] == curr_pattern_index) {
507	            found = true;
508	        }
509	    }
510	    // if this edge isn't annotated with the current pack pattern
511	    // no need to explore it
512	    if (!found) {
513	        return;
514	    }
515	
516	    found = false;
517	    // iterate over the expansion edge output pins
518	    for (i = 0; i < expansion_edge->num_output_pins; i++) {
519	        // check if expansion_edge parent node is a primitive (i.e num_nodes = 0)
520	        if (expansion_edge->output_pins[i]->is_primitive_pin()) {
521	            destination_pb_graph_node = expansion_edge->output_pins[i]->parent_node;
522	            VTR_ASSERT(found == false);
523	            /* Check assumption that each forced net has only one fan-out */
524	            /* This is the destination node */
525	            found = true;
526	
527	            // Keep track of the last primitive from this pb_graph_node that was added to a packing pattern.
528	            const t_pack_pattern_block* destination_pb_temp = last_added_pattern_block[destination_pb_graph_node];
529	            // if this pb_graph_node (primitive) is not added to the packing pattern already, add it and expand all its edges
530	            if (destination_pb_temp == nullptr || destination_pb_temp->pattern_index != curr_pattern_index) {
531	                // a primitive that belongs to this pack pattern is found: 1) create a new pattern block,
532	                // 2) assign an id to this pattern block, 3) increment the number of found blocks belonging to this
533	                // pattern and 4) expand all its edges to find the other primitives that belong to this pattern
534	                destination_block = new t_pack_pattern_block();
535	                packing_pattern.base_cost += compute_primitive_base_cost(destination_pb_graph_node);
536	                destination_block->block_id = *L_num_blocks;
537	                (*L_num_blocks)++;
538	                last_added_pattern_block[destination_pb_graph_node] = destination_block;
539	                destination_block->pattern_index = curr_pattern_index;
540	                destination_block->pb_type = destination_pb_graph_node->pb_type;
541	
542	                // explore the inputs to this primitive
543	                for (iport = 0; iport < destination_pb_graph_node->num_input_ports; iport++) {
544	                    for (ipin = 0; ipin < destination_pb_graph_node->num_input_pins[iport]; ipin++) {
545	                        for (iedge = 0; iedge < destination_pb_graph_node->input_pins[iport][ipin].num_input_edges; iedge++) {
546	                            backward_expand_pack_pattern_from_edge(destination_pb_graph_node->input_pins[iport][ipin].input_edges[iedge],
547	                                                                   packing_pattern,
548	                                                                   &destination_pb_graph_node->input_pins[iport][ipin],
549	                                                                   destination_block, L_num_blocks,
550	                                                                   last_added_pattern_block);
551	                        }
552	                    }
553	                }
554	
555	                // explore the outputs of this primitive
556	                for (iport = 0; iport < destination_pb_graph_node->num_output_ports; iport++) {
557	                    for (ipin = 0; ipin < destination_pb_graph_node->num_output_pins[iport]; ipin++) {
558	                        for (iedge = 0; iedge < destination_pb_graph_node->output_pins[iport][ipin].num_output_edges; iedge++) {
559	                            forward_expand_pack_pattern_from_edge(destination_pb_graph_node->output_pins[iport][ipin].output_edges[iedge],
560	                                                                  packing_pattern, L_num_blocks, false,
561	                                                                  last_added_pattern_block);
562	                        }
563	                    }
564	                }
565	
566	                // explore the clock pins of this primitive
567	                for (iport = 0; iport < destination_pb_graph_node->num_clock_ports; iport++) {
568	                    for (ipin = 0; ipin < destination_pb_graph_node->num_clock_pins[iport]; ipin++) {
569	                        for (iedge = 0; iedge < destination_pb_graph_node->clock_pins[iport][ipin].num_input_edges; iedge++) {
570	                            backward_expand_pack_pattern_from_edge(destination_pb_graph_node->clock_pins[iport][ipin].input_edges[iedge],
571	                                                                   packing_pattern,
572	                                                                   &destination_pb_graph_node->clock_pins[iport][ipin],
573	                                                                   destination_block, L_num_blocks, last_added_pattern_block);
574	                        }
575	                    }
576	                }
577	            }
578	
579	            // if this pb_graph_node (primitive) should be added to the pack pattern blocks
580	            if (last_added_pattern_block[destination_pb_graph_node]->pattern_index == curr_pattern_index) {
581	                // if this pb_graph_node is known to be the root of the chain, update the root block and root pin
582	                if (make_root_of_chain == true) {
583	                    packing_pattern.chain_root_pins = {{expansion_edge->output_pins[i]}};
584	                    packing_pattern.root_block = destination_block;
585	                }
586	            }
587	
588	            // the expansion_edge parent node is not a primitive
589	        } else {
590	            // continue expanding forward
591	            for (j = 0; j < expansion_edge->output_pins[i]->num_output_edges; j++) {
592	                if (expansion_edge->output_pins[i]->output_edges[j]->infer_pattern == true) {
593	                    forward_expand_pack_pattern_from_edge(expansion_edge->output_pins[i]->output_edges[j],
594	                                                          packing_pattern,
595	                                                          L_num_blocks,
596	                                                          make_root_of_chain,
597	                                                          last_added_pattern_block);
598	                } else {
599	                    for (k = 0; k < expansion_edge->output_pins[i]->output_edges[j]->num_pack_patterns; k++) {
600	                        if (expansion_edge->output_pins[i]->output_edges[j]->pack_pattern_indices[k] == curr_pattern_index) {
601	                            if (found == true) {
602	                                /* Check assumption that each forced net has only one fan-out */
603	                                VPR_FATAL_ERROR(VPR_ERROR_PACK,
604	                                                "Invalid packing pattern defined.  Multi-fanout nets not supported when specifying pack patterns.\n"
605	                                                "Problem on %s[%d].%s[%d] for pattern %s\n",
606	                                                expansion_edge->output_pins[i]->parent_node->pb_type->name,
607	                                                expansion_edge->output_pins[i]->parent_node->placement_index,
608	                                                expansion_edge->output_pins[i]->port->name,
609	                                                expansion_edge->output_pins[i]->pin_number,
610	                                                packing_pattern.name);
611	                            }
612	                            found = true;
613	                            forward_expand_pack_pattern_from_edge(expansion_edge->output_pins[i]->output_edges[j],
614	                                                                  packing_pattern,
615	                                                                  L_num_blocks,
616	                                                                  make_root_of_chain,
617	                                                                  last_added_pattern_block);
618	                        }
619	                    } // End for pack patterns of output edge
620	                }
621	            } // End for number of output edges
622	        }
623	    } // End for output pins of expansion edge
624	}
