626	/**
627	 * Find if driver of edge is in the same pattern, if yes, add to pattern
628	 *  Convention: Connections are made on backward expansion only (to make future multi-
629	 *               fanout support easier) so this function must update both source and
630	 *               destination blocks
631	 */
632	static void backward_expand_pack_pattern_from_edge(const t_pb_graph_edge* expansion_edge,
633	                                                   t_pack_patterns& packing_pattern,
634	                                                   t_pb_graph_pin* destination_pin,
635	                                                   t_pack_pattern_block* destination_block,
636	                                                   int* L_num_blocks,
637	                                                   std::unordered_map<t_pb_graph_node*, t_pack_pattern_block*>& last_added_pattern_block) {
638	    int i, j, k;
639	    int iport, ipin, iedge;
640	    bool found; /* Error checking, ensure only one fan-out for each pattern net */
641	    t_pack_pattern_block* source_block = nullptr;
642	    t_pb_graph_node* source_pb_graph_node = nullptr;
643	    t_pack_pattern_connections* pack_pattern_connection = nullptr;
644	    int curr_pattern_index = packing_pattern.index;
645	
646	    found = expansion_edge->infer_pattern;
647	    // if the pack pattern shouldn't be inferred check if the expansion
648	    // edge is annotated with the current pack pattern we are expanding
649	    for (i = 0; !found && i < expansion_edge->num_pack_patterns; i++) {
650	        if (expansion_edge->pack_pattern_indices[i] == curr_pattern_index) {
651	            found = true;
652	        }
653	    }
654	
655	    // if this edge isn't annotated with the current pack pattern
656	    // no need to explore it
657	    if (!found) {
658	        return;
659	    }
660	
661	    found = false;
662	    // iterate over all the drivers of this edge
663	    for (i = 0; i < expansion_edge->num_input_pins; i++) {
664	        // check if the expansion_edge parent node is a primitive
665	        if (expansion_edge->input_pins[i]->is_primitive_pin()) {
666	            source_pb_graph_node = expansion_edge->input_pins[i]->parent_node;
667	            VTR_ASSERT(found == false);
668	            /* Check assumption that each forced net has only one fan-out */
669	            /* This is the source node for destination */
670	            found = true;
671	
672	            /* If this pb_graph_node is part not of the current pattern index, put it in and expand all its edges */
673	            source_block = last_added_pattern_block[source_pb_graph_node];
674	            if (source_block == nullptr || source_block->pattern_index != curr_pattern_index) {
675	                source_block = new t_pack_pattern_block();
676	                source_block->block_id = *L_num_blocks;
677	                (*L_num_blocks)++;
678	                packing_pattern.base_cost += compute_primitive_base_cost(source_pb_graph_node);
679	                last_added_pattern_block[source_pb_graph_node] = source_block;
680	                source_block->pattern_index = curr_pattern_index;
681	                source_block->pb_type = source_pb_graph_node->pb_type;
682	
683	                if (packing_pattern.root_block == nullptr) {
684	                    packing_pattern.root_block = source_block;
685	                }
686	
687	                // explore the inputs of this primitive
688	                for (iport = 0; iport < source_pb_graph_node->num_input_ports; iport++) {
689	                    for (ipin = 0; ipin < source_pb_graph_node->num_input_pins[iport]; ipin++) {
690	                        for (iedge = 0; iedge < source_pb_graph_node->input_pins[iport][ipin].num_input_edges; iedge++) {
691	                            backward_expand_pack_pattern_from_edge(source_pb_graph_node->input_pins[iport][ipin].input_edges[iedge],
692	                                                                   packing_pattern,
693	                                                                   &source_pb_graph_node->input_pins[iport][ipin],
694	                                                                   source_block,
695	                                                                   L_num_blocks,
696	                                                                   last_added_pattern_block);
697	                        }
698	                    }
699	                }
700	
701	                // explore the outputs of this primitive
702	                for (iport = 0; iport < source_pb_graph_node->num_output_ports; iport++) {
703	                    for (ipin = 0; ipin < source_pb_graph_node->num_output_pins[iport]; ipin++) {
704	                        for (iedge = 0; iedge < source_pb_graph_node->output_pins[iport][ipin].num_output_edges; iedge++) {
705	                            forward_expand_pack_pattern_from_edge(source_pb_graph_node->output_pins[iport][ipin].output_edges[iedge],
706	                                                                  packing_pattern,
707	                                                                  L_num_blocks,
708	                                                                  false,
709	                                                                  last_added_pattern_block);
710	                        }
711	                    }
712	                }
713	
714	                // explore the clock pins of this primitive
715	                for (iport = 0; iport < source_pb_graph_node->num_clock_ports; iport++) {
716	                    for (ipin = 0; ipin < source_pb_graph_node->num_clock_pins[iport]; ipin++) {
717	                        for (iedge = 0; iedge < source_pb_graph_node->clock_pins[iport][ipin].num_input_edges; iedge++) {
718	                            backward_expand_pack_pattern_from_edge(source_pb_graph_node->clock_pins[iport][ipin].input_edges[iedge],
719	                                                                   packing_pattern,
720	                                                                   &source_pb_graph_node->clock_pins[iport][ipin],
721	                                                                   source_block,
722	                                                                   L_num_blocks,
723	                                                                   last_added_pattern_block);
724	                        }
725	                    }
726	                }
727	            }
728	
729	            if (destination_pin != nullptr) {
730	                VTR_ASSERT(last_added_pattern_block[source_pb_graph_node]->pattern_index == curr_pattern_index);
731	                source_block = last_added_pattern_block[source_pb_graph_node];
732	                pack_pattern_connection = new t_pack_pattern_connections();
733	                pack_pattern_connection->from_block = source_block;
734	                pack_pattern_connection->from_pin = expansion_edge->input_pins[i];
735	                pack_pattern_connection->to_block = destination_block;
736	                pack_pattern_connection->to_pin = destination_pin;
737	                pack_pattern_connection->next = source_block->connections;
738	                source_block->connections = pack_pattern_connection;
739	
740	                pack_pattern_connection = new t_pack_pattern_connections();
741	                pack_pattern_connection->from_block = source_block;
742	                pack_pattern_connection->from_pin = expansion_edge->input_pins[i];
743	                pack_pattern_connection->to_block = destination_block;
744	                pack_pattern_connection->to_pin = destination_pin;
745	                pack_pattern_connection->next = destination_block->connections;
746	                destination_block->connections = pack_pattern_connection;
747	
748	                if (source_block == destination_block) {
749	                    VPR_FATAL_ERROR(VPR_ERROR_PACK,
750	                                    "Invalid packing pattern defined. Source and destination block are the same (%s).\n",
751	                                    source_block->pb_type->name);
752	                }
753	            }
754	
755	            // expansion edge parent is not a primitive
756	        } else {
757	            // check if this input pin of the expansion edge has no driving pin
758	            if (expansion_edge->input_pins[i]->num_input_edges == 0) {
759	                // check if this input pin of the expansion edge belongs to a root block (i.e doesn't have a parent block)
760	                if (expansion_edge->input_pins[i]->parent_node->pb_type->is_root()) {
761	                    // This pack pattern extends to CLB (root pb block) input pin,
762	                    // thus it extends across multiple logic blocks, treat as a chain
763	                    packing_pattern.is_chain = true;
764	                    // since this input pin has not driving nets, expand in the forward direction instead
765	                    forward_expand_pack_pattern_from_edge(expansion_edge,
766	                                                          packing_pattern,
767	                                                          L_num_blocks,
768	                                                          true,
769	                                                          last_added_pattern_block);
770	                }
771	                // this input pin of the expansion edge has a driving pin
772	            } else {
773	                // iterate over all the driving edges of this input pin
774	                for (j = 0; j < expansion_edge->input_pins[i]->num_input_edges; j++) {
775	                    // if pattern should be inferred for this edge continue the expansion backwards
776	                    if (expansion_edge->input_pins[i]->input_edges[j]->infer_pattern == true) {
777	                        backward_expand_pack_pattern_from_edge(expansion_edge->input_pins[i]->input_edges[j],
778	                                                               packing_pattern,
779	                                                               destination_pin,
780	                                                               destination_block,
781	                                                               L_num_blocks,
782	                                                               last_added_pattern_block);
783	                        // if pattern shouldn't be inferred
784	                    } else {
785	                        // check if this input pin edge is annotated with the current pattern
786	                        for (k = 0; k < expansion_edge->input_pins[i]->input_edges[j]->num_pack_patterns; k++) {
787	                            if (expansion_edge->input_pins[i]->input_edges[j]->pack_pattern_indices[k] == curr_pattern_index) {
788	                                VTR_ASSERT(found == false);
789	                                /* Check assumption that each forced net has only one fan-out */
790	                                found = true;
791	                                backward_expand_pack_pattern_from_edge(expansion_edge->input_pins[i]->input_edges[j],
792	                                                                       packing_pattern,
793	                                                                       destination_pin,
794	                                                                       destination_block,
795	                                                                       L_num_blocks,
796	                                                                       last_added_pattern_block);
797	                            }
798	                        }
799	                    }
800	                }
801	            }
802	        }
803	    }
804	}
