806	t_pb_graph_node* Prepacker::get_expected_lowest_cost_primitive_for_atom_block(const AtomBlockId blk_id,
807	                                                                              const std::vector<t_logical_block_type>& logical_block_types) const {
808	    float cost, best_cost;
809	    t_pb_graph_node *current, *best;
810	
811	    best_cost = UNDEFINED;
812	    best = nullptr;
813	    current = nullptr;
814	    for (const t_logical_block_type& type : logical_block_types) {
815	        cost = UNDEFINED;
816	        current = get_expected_lowest_cost_primitive_for_atom_block_in_pb_graph_node(blk_id, type.pb_graph_head, &cost);
817	        if (cost != UNDEFINED) {
818	            if (best_cost == UNDEFINED || best_cost > cost) {
819	                best_cost = cost;
820	                best = current;
821	            }
822	        }
823	    }
824	
825	    return best;
826	}
