828	/**
829	 * Pre-pack atoms in netlist to molecules
830	 * 1.  Single atoms are by definition a molecule.
831	 * 2.  Forced pack molecules are groupings of atoms that matches a t_pack_pattern definition.
832	 * 3.  Chained molecules are molecules that follow a carry-chain style pattern,
833	 *     ie. a single linear chain that can be split across multiple complex blocks
834	 */
835	void Prepacker::alloc_and_load_pack_molecules(std::multimap<AtomBlockId, PackMoleculeId>& atom_molecules_multimap,
836	                                              const AtomNetlist& atom_nlist,
837	                                              const LogicalModels& models,
838	                                              const std::vector<t_logical_block_type>& logical_block_types) {
839	    std::vector<bool> is_used(list_of_pack_patterns.size(), false);
840	
841	    /* Find forced pack patterns
842	     * Simplifying assumptions: Each atom can map to at most one molecule,
843	     *                          use first-fit mapping based on priority of pattern
844	     * TODO: Need to investigate better mapping strategies than first-fit
845	     */
846	    size_t num_packing_patterns = list_of_pack_patterns.size();
847	    for (size_t i = 0; i < num_packing_patterns; i++) {
848	        /* Skip pack patterns for modes that are disabled for packing,
849	         * Ensure no resources in unpackable modes will be mapped during pre-packing stage 
850	         */
851	        if ((nullptr != list_of_pack_patterns[i].root_block->pb_type->parent_mode)
852	            && (true == list_of_pack_patterns[i].root_block->pb_type->parent_mode->disable_packing)) {
853	            continue;
854	        }
855	
856	        size_t best_pattern = 0;
857	        for (size_t j = 1; j < num_packing_patterns; j++) {
858	            if (is_used[best_pattern]) {
859	                best_pattern = j;
860	            } else if (is_used[j] == false && compare_pack_pattern(&list_of_pack_patterns[j], &list_of_pack_patterns[best_pattern]) == 1) {
861	                best_pattern = j;
862	            }
863	        }
864	        VTR_ASSERT(is_used[best_pattern] == false);
865	        is_used[best_pattern] = true;
866	
867	        auto blocks = atom_nlist.blocks();
868	        for (auto blk_iter = blocks.begin(); blk_iter != blocks.end(); ++blk_iter) {
869	            auto blk_id = *blk_iter;
870	
871	            PackMoleculeId cur_molecule_id = try_create_molecule(best_pattern,
872	                                                                 blk_id,
873	                                                                 atom_molecules_multimap,
874	                                                                 atom_nlist);
875	
876	            // If the molecule could not be created, move to the next block.
877	            if (!cur_molecule_id.is_valid())
878	                continue;
879	
880	            /* In the event of multiple molecules with the same atom block pattern,
881	             * bias to use the molecule with less costly physical resources first */
882	            /* TODO: Need to normalize magical number 100 */
883	            t_pack_molecule& cur_molecule = pack_molecules_[cur_molecule_id];
884	            cur_molecule.base_gain = cur_molecule.atom_block_ids.size() - (cur_molecule.pack_pattern->base_cost / 100);
885	
886	            //Note: atom_molecules is an (ordered) multimap so the last molecule
887	            //      inserted for a given blk_id will be the last valid element
888	            //      in the equal_range
889	            auto rng = atom_molecules_multimap.equal_range(blk_id); //The range of molecules matching this block
890	            bool range_empty = (rng.first == rng.second);
891	            bool cur_was_last_inserted = false;
892	            if (!range_empty) {
893	                auto last_valid_iter = --rng.second; //Iterator to last element (only valid if range is not empty)
894	                cur_was_last_inserted = (last_valid_iter->second == cur_molecule_id);
895	            }
896	            if (range_empty || !cur_was_last_inserted) {
897	                /* molecule did not cover current atom (possibly because molecule created is
898	                 * part of a long chain that extends past multiple logic blocks), try again */
899	                --blk_iter;
900	            }
901	        }
902	    }
903	
904	    /* List all atom blocks as a molecule for blocks that do not belong to any molecules.
905	     * This allows the packer to be consistent as it now packs molecules only instead of atoms and molecules
906	     *
907	     * If a block belongs to a molecule, then carrying the single atoms around can make the packing problem
908	     * more difficult because now it needs to consider splitting molecules.
909	     */
910	    for (auto blk_id : atom_nlist.blocks()) {
911	        t_pb_graph_node* best = get_expected_lowest_cost_primitive_for_atom_block(blk_id, logical_block_types);
912	        if (!best) {
913	            VPR_FATAL_ERROR(VPR_ERROR_PACK, "Failed to find any location to pack primitive of type '%s' in architecture",
914	                            models.get_model(atom_nlist.block_model(blk_id)).name.c_str());
915	        }
916	
917	        VTR_ASSERT_SAFE(nullptr != best);
918	
919	        expected_lowest_cost_pb_gnode[blk_id] = best;
920	
921	        auto rng = atom_molecules_multimap.equal_range(blk_id);
922	        bool rng_empty = (rng.first == rng.second);
923	        if (rng_empty) {
924	            PackMoleculeId new_molecule_id = PackMoleculeId(pack_molecules_.size());
925	            t_pack_molecule new_molecule;
926	            new_molecule.type = e_pack_pattern_molecule_type::MOLECULE_SINGLE_ATOM;
927	            new_molecule.root = 0;
928	            new_molecule.pack_pattern = nullptr;
929	
930	            new_molecule.atom_block_ids = {blk_id};
931	
932	            new_molecule.base_gain = 1;
933	            new_molecule.chain_id = MoleculeChainId::INVALID();
934	
935	            atom_molecules_multimap.insert({blk_id, new_molecule_id});
936	            pack_molecules_.push_back(std::move(new_molecule));
937	            pack_molecule_ids_.push_back(new_molecule_id);
938	        }
939	    }
940	
941	    if (getEchoEnabled() && isEchoFileEnabled(E_ECHO_PRE_PACKING_MOLECULES_AND_PATTERNS)) {
942	        print_pack_molecules(getEchoFileName(E_ECHO_PRE_PACKING_MOLECULES_AND_PATTERNS),
943	                             list_of_pack_patterns, num_packing_patterns,
944	                             pack_molecules_,
945	                             atom_nlist);
946	    }
947	}
