949	static void free_pack_pattern_block(t_pack_pattern_block* pattern_block, t_pack_pattern_block** pattern_block_list) {
950	    t_pack_pattern_connections *connection, *next;
951	    if (pattern_block == nullptr || pattern_block->block_id == UNDEFINED) {
952	        /* already traversed, return */
953	        return;
954	    }
955	    pattern_block_list[pattern_block->block_id] = pattern_block;
956	    pattern_block->block_id = UNDEFINED;
957	    connection = pattern_block->connections;
958	    while (connection) {
959	        free_pack_pattern_block(connection->from_block, pattern_block_list);
960	        free_pack_pattern_block(connection->to_block, pattern_block_list);
961	        next = connection->next;
962	        delete connection;
963	        connection = next;
964	    }
965	}
