967	/**
968	 * Given a pattern and an atom block to serve as the root block, determine if
969	 * the candidate atom block serving as the root node matches the pattern.
970	 * If yes, return the molecule with this atom block as the root, if not, return NULL
971	 *
972	 * Limitations: Currently assumes that forced pack nets must be single-fanout as
973	 *              this covers all the reasonable architectures we wanted. More complicated
974	 *              structures should probably be handled either downstream (general packing)
975	 *              or upstream (in tech mapping).
976	 *              If this limitation is too constraining, code is designed so that this limitation can be removed
977	 *
978	 * Side Effect: If successful, link atom to molecule
979	 */
980	PackMoleculeId Prepacker::try_create_molecule(const int pack_pattern_index,
981	                                              AtomBlockId blk_id,
982	                                              std::multimap<AtomBlockId, PackMoleculeId>& atom_molecules_multimap,
983	                                              const AtomNetlist& atom_nlist) {
984	    auto pack_pattern = &list_of_pack_patterns[pack_pattern_index];
985	
986	    // Check pack pattern validity
987	    if (pack_pattern == nullptr || pack_pattern->num_blocks == 0 || pack_pattern->root_block == nullptr) {
988	        return PackMoleculeId::INVALID();
989	    }
990	
991	    // If a chain pattern extends beyond a single logic block, we must find
992	    // the furthest blk_id up the chain that is not mapped to a molecule yet.
993	    if (pack_pattern->is_chain) {
994	        blk_id = find_new_root_atom_for_chain(blk_id, pack_pattern, atom_molecules_multimap, atom_nlist);
995	        if (!blk_id) return PackMoleculeId::INVALID();
996	    }
997	
998	    PackMoleculeId new_molecule_id = PackMoleculeId(pack_molecules_.size());
999	    t_pack_molecule molecule;
1000	    molecule.base_gain = 0.f;
1001	    molecule.type = e_pack_pattern_molecule_type::MOLECULE_FORCED_PACK;
1002	    molecule.pack_pattern = pack_pattern;
1003	    molecule.atom_block_ids = std::vector<AtomBlockId>(pack_pattern->num_blocks); //Initializes invalid
1004	    molecule.root = pack_pattern->root_block->block_id;
1005	    molecule.chain_id = MoleculeChainId::INVALID();
1006	
1007	    if (!try_expand_molecule(molecule, blk_id, atom_molecules_multimap, atom_nlist)) {
1008	        // Failed to create molecule
1009	        return PackMoleculeId::INVALID();
1010	    }
1011	
1012	    // Success! commit molecule
1013	
1014	    // update chain info for chain molecules
1015	    if (molecule.pack_pattern->is_chain) {
1016	        init_molecule_chain_info(blk_id, molecule, pack_molecules_, atom_molecules_multimap, chain_info_, atom_nlist);
1017	    }
1018	
1019	    // update the atom_molcules with the atoms that are mapped to this molecule
1020	    for (int i = 0; i < molecule.pack_pattern->num_blocks; i++) {
1021	        auto blk_id2 = molecule.atom_block_ids[i];
1022	        if (!blk_id2) {
1023	            VTR_ASSERT(molecule.pack_pattern->is_block_optional[i]);
1024	            continue;
1025	        }
1026	
1027	        atom_molecules_multimap.insert({blk_id2, new_molecule_id});
1028	    }
1029	
1030	    pack_molecules_.push_back(std::move(molecule));
1031	    pack_molecule_ids_.push_back(new_molecule_id);
1032	    return new_molecule_id;
1033	}
