1035	/**
1036	 * Determine if an atom block can match with the pattern to from a molecule.
1037	 *
1038	 * This function takes a molecule that represents a packing pattern. It also
1039	 * takes a (netlist) atom block represented by blk_id which matches the
1040	 * root primitive of this packing pattern. Using this atom block and the structure
1041	 * of the packing pattern, this function tries to fill all the available positions
1042	 * in the packing pattern. If all the non-optional primitive positions in the
1043	 * pattern are filled return true, return false otherwise.
1044	 *      molecule       : the molecule we are trying to expand
1045	 *      atom_molecules : map of atom block ids that are assigned a molecule and a pointer to this molecule
1046	 *      blk_id         : chosen to be the root of this molecule and the code is expanding from
1047	 */
1048	static bool try_expand_molecule(t_pack_molecule& molecule,
1049	                                const AtomBlockId blk_id,
1050	                                const std::multimap<AtomBlockId, PackMoleculeId>& atom_molecules,
1051	                                const AtomNetlist& atom_nlist) {
1052	    // root block of the pack pattern, which is the starting point of this pattern
1053	    const auto pattern_root_block = molecule.pack_pattern->root_block;
1054	    // bool array indicating whether a position in a pack pattern is optional or should
1055	    // be filled with an atom for legality
1056	    const auto is_block_optional = molecule.pack_pattern->is_block_optional;
1057	
1058	    // create a queue of pattern block and atom block id suggested for this block
1059	    std::queue<std::pair<t_pack_pattern_block*, AtomBlockId>> pattern_block_queue;
1060	    // initialize the queue with the pattern root block and the matching atom block
1061	    pattern_block_queue.push(std::make_pair(pattern_root_block, blk_id));
1062	
1063	    // do breadth first search by walking through the pack pattern structure along
1064	    // with the atom netlist structure
1065	    while (!pattern_block_queue.empty()) {
1066	        // get the front pattern block, atom block id pair from the queue
1067	        const auto pattern_block_atom_pair = pattern_block_queue.front();
1068	        const auto pattern_block = pattern_block_atom_pair.first;
1069	        const auto block_id = pattern_block_atom_pair.second;
1070	
1071	        // remove the front of the queue
1072	        pattern_block_queue.pop();
1073	
1074	        // get the atom block id of the atom occupying this primitive position in this molecule
1075	        auto molecule_atom_block_id = molecule.atom_block_ids[pattern_block->block_id];
1076	
1077	        // if this primitive position in this molecule is already visited and
1078	        // matches block in the atom netlist go to the next node in the queue
1079	        if (molecule_atom_block_id && molecule_atom_block_id == block_id) {
1080	            continue;
1081	        }
1082	
1083	        if (!block_id || !primitive_type_feasible(block_id, pattern_block->pb_type) || (molecule_atom_block_id && molecule_atom_block_id != block_id) || atom_molecules.find(block_id) != atom_molecules.end()) {
1084	            // Stopping conditions, if:
1085	            // 1) this is an invalid atom block (nothing)
1086	            // 2) this atom block cannot fit in this primitive type
1087	            // 3) this primitive is occupied by another block
1088	            // 4) this atom block is already used by another molecule
1089	            // then if the molecule cannot be formed without placing an atom
1090	            // at that primitive position, then creating this molecule has failed
1091	            // otherwise go to the next atom block and its corresponding pattern block
1092	            if (!is_block_optional[pattern_block->block_id]) {
1093	                return false;
1094	            }
1095	            continue;
1096	        }
1097	
1098	        // set this node in the molecule as visited
1099	        molecule.atom_block_ids[pattern_block->block_id] = block_id;
1100	
1101	        // starting from the first connections, add all the connections of this block to the queue
1102	        auto block_connection = pattern_block->connections;
1103	
1104	        while (block_connection != nullptr) {
1105	            // this block is the driver of this connection
1106	            if (block_connection->from_block == pattern_block) {
1107	                // find the block this connection is driving and add it to the queue
1108	                auto sink_blk_id = get_sink_block(block_id, *block_connection, atom_nlist);
1109	                // add this sink block id with its corresponding pattern block to the queue
1110	                pattern_block_queue.push(std::make_pair(block_connection->to_block, sink_blk_id));
1111	                // this block is being driven by this connection
1112	            } else if (block_connection->to_block == pattern_block) {
1113	                // find the block that is driving this connection and it to the queue
1114	                auto driver_blk_id = get_driving_block(block_id, *block_connection, atom_nlist);
1115	                // add this driver block id with its corresponding pattern block to the queue
1116	                pattern_block_queue.push(std::make_pair(block_connection->from_block, driver_blk_id));
1117	            }
1118	
1119	            // this block should be either driving or driven by the connection
1120	            VTR_ASSERT(block_connection->from_block == pattern_block || block_connection->to_block == pattern_block);
1121	            // go to the next connection of this pattern block
1122	            block_connection = block_connection->next;
1123	        }
1124	    }
1125	    // if all non-optional positions in the pack pattern have atoms
1126	    // mapped to them, then this molecule is valid
1127	    return true;
1128	}
