1130	/**
1131	 * Find the atom block in the netlist driven by this pin of the input atom block
1132	 * If doesn't exist return AtomBlockId::INVALID()
1133	 *      TODO: Limitation — For pack patterns other than chains, 
1134	 *            the block should be driven by only one block
1135	 *      block_id   : id of the atom block that is driving the net connected to the sink block
1136	 *      connections : pack pattern connections from the given block
1137	 */
1138	static AtomBlockId get_sink_block(const AtomBlockId block_id,
1139	                                  const t_pack_pattern_connections& connections,
1140	                                  const AtomNetlist& atom_nlist) {
1141	    const t_model_ports* from_port_model = connections.from_pin->port->model_port;
1142	    const int from_pin_number = connections.from_pin->pin_number;
1143	    auto from_port_id = atom_nlist.find_atom_port(block_id, from_port_model);
1144	
1145	    const t_model_ports* to_port_model = connections.to_pin->port->model_port;
1146	    const int to_pin_number = connections.to_pin->pin_number;
1147	    const auto& to_pb_type = connections.to_block->pb_type;
1148	
1149	    if (!from_port_id.is_valid()) {
1150	        return AtomBlockId::INVALID();
1151	    }
1152	
1153	    auto net_id = atom_nlist.port_net(from_port_id, from_pin_number);
1154	    if (!net_id.is_valid()) {
1155	        return AtomBlockId::INVALID();
1156	    }
1157	
1158	    const auto& net_sinks = atom_nlist.net_sinks(net_id);
1159	    // Iterate through all sink blocks and check whether any of them
1160	    // is compatible with the block specified in the pack pattern.
1161	    bool connected_to_latch = false;
1162	    AtomBlockId pattern_sink_block_id = AtomBlockId::INVALID();
1163	    for (const auto& sink_pin_id : net_sinks) {
1164	        auto sink_block_id = atom_nlist.pin_block(sink_pin_id);
1165	        // If the sink block has a clock, it is considered stateful (e.g., a latch or flip-flop).
1166	        // Mark this so we can later decide whether to drop the block based on the net’s fanout.
1167	        if (!atom_nlist.block_is_combinational(sink_block_id)) {
1168	            connected_to_latch = true;
1169	        }
1170	        if (primitive_type_feasible(sink_block_id, to_pb_type)) {
1171	            auto to_port_id = atom_nlist.find_atom_port(sink_block_id, to_port_model);
1172	            auto to_pin_id = atom_nlist.find_pin(to_port_id, BitIndex(to_pin_number));
1173	            if (to_pin_id == sink_pin_id) {
1174	                pattern_sink_block_id = sink_block_id;
1175	            }
1176	        }
1177	    }
1178	    // If the number of sinks is greater than 1, and one of the connected blocks is a latch,
1179	    // then we drop the block to avoid a situation where only registers or unregistered output
1180	    // of the block can use the output pin.
1181	    // TODO: This is a conservative assumption, and ideally we need to do analysis of the architecture
1182	    // before to determine which pattern is supported by the architecture.
1183	    if (connected_to_latch && net_sinks.size() > 1) {
1184	        pattern_sink_block_id = AtomBlockId::INVALID();
1185	    }
1186	    return pattern_sink_block_id;
1187	}
