1189	/**
1190	 * Find the atom block in the netlist driving this pin of the input atom block
1191	 * If doesn't exist return AtomBlockId::INVALID()
1192	 * Limitation: This driving block should be driving only the input block
1193	 *      block_id   : id of the atom block that is connected to a net driven by the driving block
1194	 *      connections : pack pattern connections from the given block
1195	 */
1196	static AtomBlockId get_driving_block(const AtomBlockId block_id,
1197	                                     const t_pack_pattern_connections& connections,
1198	                                     const AtomNetlist& atom_nlist) {
1199	    auto to_port_model = connections.to_pin->port->model_port;
1200	    auto to_pin_number = connections.to_pin->pin_number;
1201	    auto to_port_id = atom_nlist.find_atom_port(block_id, to_port_model);
1202	
1203	    if (!to_port_id.is_valid()) {
1204	        return AtomBlockId::INVALID();
1205	    }
1206	
1207	    auto net_id = atom_nlist.port_net(to_port_id, to_pin_number);
1208	    if (net_id && atom_nlist.net_sinks(net_id).size() == 1) { /* Single fanout assumption */
1209	        auto driver_blk_id = atom_nlist.net_driver_block(net_id);
1210	
1211	        if (to_port_model->is_clock) {
1212	            auto driver_blk_type = atom_nlist.block_type(driver_blk_id);
1213	
1214	            // TODO: support multi-clock primitives.
1215	            //       If the driver block is a .input block, this assertion should not
1216	            //       be triggered as the sink block might have only one input pin, which
1217	            //       would be a clock pin in case the sink block primitive is a clock generator,
1218	            //       resulting in a pin_number == 0.
1219	            VTR_ASSERT(to_pin_number == 1 || (to_pin_number == 0 && driver_blk_type == AtomBlockType::INPAD));
1220	        }
1221	
1222	        return driver_blk_id;
1223	    }
1224	
1225	    return AtomBlockId::INVALID();
1226	}
