1228	static std::unordered_set<t_pb_type*> get_pattern_blocks(const t_pack_patterns& pack_pattern) {
1229	    std::unordered_set<t_pb_type*> pattern_blocks;
1230	
1231	    t_pack_pattern_connections* connections = pack_pattern.root_block->connections;
1232	    if (connections == nullptr) {
1233	        return pattern_blocks;
1234	    }
1235	    std::unordered_set<t_pb_graph_pin*> visited_from_pins;
1236	    std::unordered_set<t_pb_graph_pin*> visited_to_pins;
1237	    std::queue<t_pack_pattern_block*> pack_pattern_blocks;
1238	    pack_pattern_blocks.push(connections->from_block);
1239	
1240	    /** Start from the root block of the pack pattern and add the connected block to the queue */
1241	    while (!pack_pattern_blocks.empty()) {
1242	        t_pack_pattern_block* current_pattern_block = pack_pattern_blocks.front();
1243	        pack_pattern_blocks.pop();
1244	        t_pack_pattern_connections* current_connenction = current_pattern_block->connections;
1245	        /*
1246	         * Iterate through all the connections of the current pattern block to
1247	         * add the connected block to the queue
1248	         */
1249	        while (current_connenction != nullptr) {
1250	            if (visited_from_pins.find(current_connenction->from_pin) != visited_from_pins.end()) {
1251	                if (visited_to_pins.find(current_connenction->to_pin) != visited_to_pins.end()) {
1252	                    /* We've already seen this connection */
1253	                    current_connenction = current_connenction->next;
1254	                    continue;
1255	                }
1256	            }
1257	            /*
1258	             * To avoid visiting the same connection twice, since it is both stored in from_pin and to_pin,
1259	             * add the from_pin and to_pin to the visited sets
1260	             */
1261	            visited_from_pins.insert(current_connenction->from_pin);
1262	            visited_to_pins.insert(current_connenction->to_pin);
1263	
1264	            /* The from_pin block belongs to the pattern block */
1265	            pattern_blocks.insert(current_connenction->from_pin->port->parent_pb_type);
1266	            pack_pattern_blocks.push(current_connenction->to_block);
1267	            current_connenction = current_connenction->next;
1268	        }
1269	    }
1270	    return pattern_blocks;
1271	}
