1324	static t_pb_graph_node* get_expected_lowest_cost_primitive_for_atom_block_in_pb_graph_node(const AtomBlockId blk_id, t_pb_graph_node* curr_pb_graph_node, float* cost) {
1325	    t_pb_graph_node *best, *cur;
1326	    float cur_cost, best_cost;
1327	    int i, j;
1328	
1329	    best = nullptr;
1330	    best_cost = UNDEFINED;
1331	    if (curr_pb_graph_node == nullptr) {
1332	        return nullptr;
1333	    }
1334	
1335	    if (curr_pb_graph_node->pb_type->blif_model != nullptr) {
1336	        if (primitive_type_feasible(blk_id, curr_pb_graph_node->pb_type)) {
1337	            cur_cost = compute_primitive_base_cost(curr_pb_graph_node);
1338	            if (best_cost == UNDEFINED || best_cost > cur_cost) {
1339	                best_cost = cur_cost;
1340	                best = curr_pb_graph_node;
1341	            }
1342	        }
1343	    } else {
1344	        for (i = 0; i < curr_pb_graph_node->pb_type->num_modes; i++) {
1345	            /* Early fail if this primitive for a mode that is disabled for packing */
1346	            if (true == curr_pb_graph_node->pb_type->modes[i].disable_packing) {
1347	                continue;
1348	            }
1349	
1350	            for (j = 0; j < curr_pb_graph_node->pb_type->modes[i].num_pb_type_children; j++) {
1351	                *cost = UNDEFINED;
1352	                cur = get_expected_lowest_cost_primitive_for_atom_block_in_pb_graph_node(blk_id, &curr_pb_graph_node->child_pb_graph_nodes[i][j][0], cost);
1353	                if (cur != nullptr) {
1354	                    if (best == nullptr || best_cost > *cost) {
1355	                        best = cur;
1356	                        best_cost = *cost;
1357	                    }
1358	                }
1359	            }
1360	        }
1361	    }
1362	
1363	    *cost = best_cost;
1364	    return best;
1365	}
