1367	/* Determine which of two pack pattern should take priority */
1368	static int compare_pack_pattern(const t_pack_patterns* pattern_a, const t_pack_patterns* pattern_b) {
1369	    float base_gain_a, base_gain_b, diff;
1370	
1371	    /* Bigger patterns should take higher priority than smaller patterns because they are harder to fit */
1372	    if (pattern_a->num_blocks > pattern_b->num_blocks) {
1373	        return 1;
1374	    } else if (pattern_a->num_blocks < pattern_b->num_blocks) {
1375	        return -1;
1376	    }
1377	
1378	    base_gain_a = pattern_a->base_cost;
1379	    base_gain_b = pattern_b->base_cost;
1380	    diff = base_gain_a - base_gain_b;
1381	
1382	    /* Less costly patterns should be used before more costly patterns */
1383	    if (diff < 0) {
1384	        return 1;
1385	    }
1386	    if (diff > 0) {
1387	        return -1;
1388	    }
1389	    return 0;
1390	}
