1392	/* A chain can extend across multiple atom blocks.  Must segment the chain to fit in an atom
1393	 * block by identifying the actual atom that forms the root of the new chain.
1394	 * Returns AtomBlockId::INVALID() if this block_index doesn't match up with any chain
1395	 *
1396	 * Assumes that the root of a chain is the primitive that starts the chain or is driven from outside the logic block
1397	 * block_index: index of current atom
1398	 * list_of_pack_pattern: ptr to current chain pattern
1399	 */
1400	static AtomBlockId find_new_root_atom_for_chain(const AtomBlockId blk_id,
1401	                                                const t_pack_patterns* list_of_pack_patterns,
1402	                                                const std::multimap<AtomBlockId, PackMoleculeId>& atom_molecules,
1403	                                                const AtomNetlist& atom_nlist) {
1404	    AtomBlockId new_root_blk_id;
1405	    t_pb_graph_pin* root_ipin;
1406	    t_pb_graph_node* root_pb_graph_node;
1407	    t_model_ports* model_port;
1408	
1409	    VTR_ASSERT(list_of_pack_patterns->is_chain == true);
1410	    VTR_ASSERT(list_of_pack_patterns->chain_root_pins.size());
1411	    root_ipin = list_of_pack_patterns->chain_root_pins[0][0];
1412	    root_pb_graph_node = root_ipin->parent_node;
1413	
1414	    if (primitive_type_feasible(blk_id, root_pb_graph_node->pb_type) == false) {
1415	        return AtomBlockId::INVALID();
1416	    }
1417	
1418	    /* Assign driver furthest up the chain that matches the root node and is unassigned to a molecule as the root */
1419	    model_port = root_ipin->port->model_port;
1420	
1421	    // find the block id of the atom block driving the input of this block
1422	    AtomBlockId driver_blk_id = atom_nlist.find_atom_pin_driver(blk_id, model_port, root_ipin->pin_number);
1423	
1424	    // if there is no driver block for this net
1425	    // then it is the furthest up the chain
1426	    if (!driver_blk_id) {
1427	        return blk_id;
1428	    }
1429	    // check if driver atom is already packed
1430	    auto rng = atom_molecules.equal_range(driver_blk_id);
1431	    bool rng_empty = (rng.first == rng.second);
1432	    if (!rng_empty) {
1433	        /* Driver is used/invalid, so current block is the furthest up the chain, return it */
1434	        return blk_id;
1435	    }
1436	
1437	    // didn't find furthest atom up the chain, keep searching further up the chain
1438	    new_root_blk_id = find_new_root_atom_for_chain(driver_blk_id, list_of_pack_patterns, atom_molecules, atom_nlist);
1439	
1440	    if (!new_root_blk_id) {
1441	        return blk_id;
1442	    } else {
1443	        return new_root_blk_id;
1444	    }
1445	}
