1447	/**
1448	 * This function takes an input pin to a root (has no parent block) pb_graph_node
1449	 * an returns a vector of all the output pins that are reachable from this input
1450	 * pin and have the same packing pattern
1451	 */
1452	
1453	static std::vector<t_pb_graph_pin*> find_end_of_path(t_pb_graph_pin* input_pin, int pattern_index) {
1454	    // Enforce some constraints on the function
1455	
1456	    // 1) the start of the path should be at the input of the root block
1457	    VTR_ASSERT(input_pin->is_root_block_pin());
1458	
1459	    // 2) this pin is an input pin to the root block
1460	    VTR_ASSERT(input_pin->num_input_edges == 0);
1461	
1462	    // create a queue of pin pointers for the breadth first search
1463	    std::queue<t_pb_graph_pin*> pins_queue;
1464	
1465	    // add the input pin to the queue
1466	    pins_queue.push(input_pin);
1467	
1468	    // found reachable output pins
1469	    std::vector<t_pb_graph_pin*> reachable_pins;
1470	
1471	    // do breadth first search till all connected
1472	    // pins are explored
1473	    while (!pins_queue.empty()) {
1474	        // get the first pin in the queue
1475	        auto current_pin = pins_queue.front();
1476	
1477	        // remove pin from queue
1478	        pins_queue.pop();
1479	
1480	        // expand search from current pin
1481	        expand_search(current_pin, pins_queue, pattern_index);
1482	
1483	        // if this is an output pin of a root block
1484	        // add to reachable output pins
1485	        if (current_pin->is_root_block_pin()
1486	            && current_pin->num_output_edges == 0) {
1487	            reachable_pins.push_back(current_pin);
1488	        }
1489	    }
1490	
1491	    return reachable_pins;
1492	}
1493	
1494	static void expand_search(const t_pb_graph_pin* input_pin, std::queue<t_pb_graph_pin*>& pins_queue, const int pattern_index) {
1495	    // If not a primitive input pin (has output edges)
1496	    // -----------------------------------------------
1497	
1498	    // iterate over all output edges at this pin
1499	    for (int iedge = 0; iedge < input_pin->num_output_edges; iedge++) {
1500	        const auto& pin_edge = input_pin->output_edges[iedge];
1501	        // if this edge is not annotated with this pattern and its pattern cannot be inferred, ignore it.
1502	        if (!pin_edge->annotated_with_pattern(pattern_index) && !pin_edge->infer_pattern) {
1503	            continue;
1504	        }
1505	
1506	        // this edge either matched the pack pattern or its pack pattern could be inferred
1507	        // iterate over all the pins of that edge and add them to the pins_queue
1508	        for (int ipin = 0; ipin < pin_edge->num_output_pins; ipin++) {
1509	            pins_queue.push(pin_edge->output_pins[ipin]);
1510	        }
1511	
1512	    } // End for pin edges
1513	
1514	    // If a primitive input pin
1515	    // ------------------------
1516	
1517	    // if this is an input pin to a primitive, it won't have
1518	    // output edges so the previous for loop won't be entered
1519	    if (input_pin->is_primitive_pin() && input_pin->num_output_edges == 0) {
1520	        // iterate over the output ports of the primitive
1521	        const auto& pin_pb_graph_node = input_pin->parent_node;
1522	        for (int iport = 0; iport < pin_pb_graph_node->num_output_ports; iport++) {
1523	            // iterate over the pins of each port
1524	            const auto& port_pins = pin_pb_graph_node->num_output_pins[iport];
1525	            for (int ipin = 0; ipin < port_pins; ipin++) {
1526	                // add primitive output pins to pins_queue to be explored
1527	                pins_queue.push(&pin_pb_graph_node->output_pins[iport][ipin]);
1528	            }
1529	        }
1530	    }
1531	
1532	    // If this is a root block output pin
1533	    // ----------------------------------
1534	
1535	    // No expansion will happen in this case
1536	}
