1538	/**
1539	 *  This function takes a chain pack pattern and a root pb_block
1540	 *  containing this pattern. Then searches for all the input pins of this
1541	 *  pb_block that are annotated with this pattern. The function then
1542	 *  identifies whether those inputs represent different starting point for
1543	 *  this pattern or are all required for building this pattern.
1544	 *
1545	 *  If this inputs represent different starting point for this pattern, it
1546	 *  means that in this pb_block there exist multiple chains that are exactly
1547	 *  the same. For example an architecture that has two separate adder chains
1548	 *  behaving exactly the same but are totally separate from each other.
1549	 *
1550	 *                        cin[0] cin[1]
1551	 *                       ---|------|---
1552	 *                       | ---    --- |
1553	 *                       | | |    | |<|---- Full Adder
1554	 *                       | ---    --- |
1555	 *   Pb_block ---------> |  |      |<-|---- Second Adder chain
1556	 *                       |  .      .  |
1557	 *                       |  .      .  |
1558	 *                       |  |<-----|--|---- First Adder chain
1559	 *                       | ---    --- |
1560	 *                       | | |    | | |
1561	 *                       | ---    --- |
1562	 *                       ---|------|---
1563	 *                       cout[0] cout[1]
1564	 *
1565	 *  In this case, the chain_root_pin array of the pack pattern is updated
1566	 *  with all the pin that represent a starting point for this pattern.
1567	 */
1568	static void find_all_equivalent_chains(t_pack_patterns* chain_pattern, const t_pb_graph_node* root_block) {
1569	    // this vector will be updated with all root_block input
1570	    // pins that are annotated with this chain pattern
1571	    std::vector<t_pb_graph_pin*> chain_input_pins;
1572	
1573	    // iterate over all the input pins of the root_block and populate
1574	    // the chain_input_pins vector
1575	    for (int iports = 0; iports < root_block->num_input_ports; iports++) {
1576	        for (int ipins = 0; ipins < root_block->num_input_pins[iports]; ipins++) {
1577	            auto& input_pin = root_block->input_pins[iports][ipins];
1578	            for (int iedge = 0; iedge < input_pin.num_output_edges; iedge++) {
1579	                if (input_pin.output_edges[iedge]->belongs_to_pattern(chain_pattern->index)) {
1580	                    chain_input_pins.push_back(&input_pin);
1581	                }
1582	            }
1583	        }
1584	    }
1585	
1586	    // if this chain has only one cluster input, then
1587	    // there is no need to proceed with the search
1588	    if (chain_input_pins.size() == 1) {
1589	        update_chain_root_pins(chain_pattern, chain_input_pins);
1590	        return;
1591	    }
1592	
1593	    // find the root block output pins reachable when starting from the chain_input_pins
1594	    // found before following the edges that are annotated with the given pack_pattern
1595	    std::vector<std::vector<t_pb_graph_pin*>> reachable_pins;
1596	
1597	    for (const auto& pin_ptr : chain_input_pins) {
1598	        auto reachable_output_pins = find_end_of_path(pin_ptr, chain_pattern->index);
1599	        // sort the reachable output pins to compare them later using set_intersection
1600	        std::stable_sort(reachable_output_pins.begin(), reachable_output_pins.end());
1601	        reachable_pins.push_back(reachable_output_pins);
1602	    }
1603	
1604	    // Search for intersections between reachable pins. Intersection
1605	    // between reachable indicates that found chain_input_pins
1606	    // represent a single chain pattern and not multiple similar
1607	    // chain patterns with multiple starting locations.
1608	    std::vector<t_pb_graph_pin*> intersection;
1609	    for (size_t i = 0; i < reachable_pins.size() - 1; i++) {
1610	        for (size_t j = 1; j < reachable_pins.size(); j++) {
1611	            std::set_intersection(reachable_pins[i].begin(), reachable_pins[i].end(),
1612	                                  reachable_pins[j].begin(), reachable_pins[j].end(),
1613	                                  std::back_inserter(intersection));
1614	            if (intersection.size()) break;
1615	        }
1616	        if (intersection.size()) break;
1617	    }
1618	
1619	    // if there are no intersections between the reachable pins,
1620	    // this each input pin represents a separate chain of type
1621	    // chain_pattern. Else, they are all representing the same
1622	    // chain.
1623	    if (intersection.empty()) {
1624	        // update the chain_root_pin array of the chain_pattern
1625	        // with all the possible starting points of the chain.
1626	        update_chain_root_pins(chain_pattern, chain_input_pins);
1627	    }
1628	}
1629	
1630	/**
1631	 *  This function takes a chain pack pattern and a vector of pin
1632	 *  pointers that represent the root pb block input pins that can connect
1633	 *  a chain to the previous pb block. The function uses the pin pointers
1634	 *  to find the primitive input pin connected to them and updates
1635	 *  the chain_root_pin array with this those pointers
1636	 *  Side Effect: Updates the chain_root_pins array of the input chain_pattern
1637	 */
1638	static void update_chain_root_pins(t_pack_patterns* chain_pattern,
1639	                                   const std::vector<t_pb_graph_pin*>& chain_input_pins) {
1640	    std::vector<std::vector<t_pb_graph_pin*>> primitive_input_pins;
1641	
1642	    std::unordered_set<t_pb_type*> pattern_blocks = get_pattern_blocks(*chain_pattern);
1643	    for (const auto pin_ptr : chain_input_pins) {
1644	        std::vector<t_pb_graph_pin*> connected_primitive_pins;
1645	        get_all_connected_primitive_pins(pin_ptr, pattern_blocks, connected_primitive_pins);
1646	
1647	        /**
1648	         * It is required that the chain pins are connected inside a complex
1649	         * block. Although it is allowed to have them disconnected in some
1650	         * modes of the block provided that there is always at least one mode
1651	         * that has them connected inside. The following assert checks for
1652	         * that.
1653	         */
1654	        VTR_ASSERT(connected_primitive_pins.size());
1655	
1656	        primitive_input_pins.push_back(connected_primitive_pins);
1657	    }
1658	
1659	    chain_pattern->chain_root_pins = primitive_input_pins;
1660	}
1661	
1662	/**
1663	 *  This function takes a pin as an input an does a depth first search on all the output edges
1664	 *  of this pin till it finds all the primitive input pins connected to this pin. For example,
1665	 *  if the input pin given to this function is the Cin pin of the cluster. This pin will return
1666	 *  the Cin pin of all the adder primitives connected to this pin. Which is for typical architectures
1667	 *  will be only one pin connected to the very first adder in the cluster.
1668	 */
1669	static void get_all_connected_primitive_pins(const t_pb_graph_pin* cluster_input_pin,
1670	                                             const std::unordered_set<t_pb_type*>& pattern_blocks,
1671	                                             std::vector<t_pb_graph_pin*>& connected_primitive_pins) {
1672	    /* Skip pins for modes that are disabled for packing*/
1673	    if ((nullptr != cluster_input_pin->parent_node->pb_type->parent_mode)
1674	        && (true == cluster_input_pin->parent_node->pb_type->parent_mode->disable_packing)) {
1675	        return;
1676	    }
1677	
1678	    for (int iedge = 0; iedge < cluster_input_pin->num_output_edges; iedge++) {
1679	        const auto& output_edge = cluster_input_pin->output_edges[iedge];
1680	        for (int ipin = 0; ipin < output_edge->num_output_pins; ipin++) {
1681	            if (output_edge->output_pins[ipin]->is_primitive_pin()) {
1682	                /** Add the output pin to the vector only if it belongs to a pb_type registered in the pattern_blocks set */
1683	                if (pattern_blocks.find(output_edge->output_pins[ipin]->parent_node->pb_type) != pattern_blocks.end()) {
1684	                    connected_primitive_pins.push_back(output_edge->output_pins[ipin]);
1685	                }
1686	            } else {
1687	                get_all_connected_primitive_pins(output_edge->output_pins[ipin], pattern_blocks, connected_primitive_pins);
1688	            }
1689	        }
1690	    }
1691	}
1692	
1693	/**
1694	 * This function initializes the chain info data structure of the molecule.
1695	 * If this is the furthest molecule up the chain, the chain_info data
1696	 * structure is created. Otherwise, the input pack_molecule is set to
1697	 * point to the same chain_info of the molecule feeding it
1698	 *
1699	 * Limitation: This function assumes that the molecules of a chain are
1700	 * created and fed to this function in order. Meaning the first molecule
1701	 * fed to the function should be the furthest molecule up the chain.
1702	 * The second one should should be the molecule directly after that one
1703	 * and so on.
1704	 */
1705	static void init_molecule_chain_info(const AtomBlockId blk_id,
1706	                                     t_pack_molecule& molecule,
1707	                                     const vtr::vector_map<PackMoleculeId, t_pack_molecule>& pack_molecules,
1708	                                     const std::multimap<AtomBlockId, PackMoleculeId>& atom_molecules,
1709	                                     vtr::vector<MoleculeChainId, t_chain_info>& chain_info,
1710	                                     const AtomNetlist& atom_nlist) {
1711	    // the input molecule to this function should have a pack
1712	    // pattern assigned to it and the input block should be valid
1713	    VTR_ASSERT(molecule.pack_pattern && blk_id);
1714	
1715	    auto root_ipin = molecule.pack_pattern->chain_root_pins[0][0];
1716	    auto model_pin = root_ipin->port->model_port;
1717	    auto pin_bit = root_ipin->pin_number;
1718	
1719	    // find the atom driving the chain input pin of this atom
1720	    auto driver_atom_id = atom_nlist.find_atom_pin_driver(blk_id, model_pin, pin_bit);
1721	
1722	    // find the molecule this driver atom is mapped to
1723	    auto itr = atom_molecules.find(driver_atom_id);
1724	
1725	    // if this is the first molecule to be created for this chain
1726	    // initialize the chain info data structure. This is the case
1727	    // if either there is no driver to the block input pin or
1728	    // if the driver is not part of a molecule
1729	    if (!driver_atom_id || itr == atom_molecules.end()) {
1730	        MoleculeChainId new_chain_id = MoleculeChainId(chain_info.size());
1731	        t_chain_info new_chain_info;
1732	        new_chain_info.is_long_chain = false;
1733	        chain_info.push_back(std::move(new_chain_info));
1734	        molecule.chain_id = new_chain_id;
1735	    } else {
1736	        // this is not the first molecule to be created for this chain
1737	        // molecule driving blk_id
1738	        PackMoleculeId prev_molecule_id = itr->second;
1739	        VTR_ASSERT(prev_molecule_id.is_valid());
1740	        const t_pack_molecule& prev_molecule = pack_molecules[prev_molecule_id];
1741	        // molecule should have chain_info associated with it
1742	        VTR_ASSERT(prev_molecule.chain_id.is_valid());
1743	        // this molecule is now known to belong to a long chain
1744	        chain_info[prev_molecule.chain_id].is_long_chain = true;
1745	        // this new molecule should share the same chain
1746	        molecule.chain_id = prev_molecule.chain_id;
1747	    }
1748	}
