1750	/**
1751	 * This function prints all the starting points of the carry chains in the architecture
1752	 */
1753	static void print_chain_starting_points(t_pack_patterns* chain_pattern) {
1754	    const auto& chain_root_pins = chain_pattern->chain_root_pins;
1755	
1756	    VTR_LOGV(chain_root_pins.size() > 1, "\nThere are %zu independent chains for chain pattern \"%s\":\n",
1757	             chain_pattern->chain_root_pins.size(), chain_pattern->name);
1758	    VTR_LOGV(chain_root_pins.size() == 1, "\nThere is one chain in this architecture called \"%s\" with the following starting points:\n", chain_pattern->name);
1759	
1760	    size_t chainId = 0;
1761	    for (const auto& chain : chain_root_pins) {
1762	        VTR_LOGV(chain_root_pins.size() > 1 && chain.size() > 1, "\n There are %zu starting points for chain id #%zu:\n", chain.size(), chainId++);
1763	        VTR_LOGV(chain_root_pins.size() > 1 && chain.size() == 1, "\n There is 1 starting point for chain id #%zu:\n", chainId++);
1764	        for (const auto& pin_ptr : chain) {
1765	            VTR_LOG("\t%s\n", pin_ptr->to_string().c_str());
1766	        }
1767	    }
1768	
1769	    VTR_LOG("\n");
1770	}
