1772	Prepacker::Prepacker(const AtomNetlist& atom_nlist,
1773	                     const LogicalModels& models,
1774	                     const std::vector<t_logical_block_type>& logical_block_types) {
1775	    vtr::ScopedStartFinishTimer prepacker_timer("Prepacker");
1776	
1777	    // Allocate the pack patterns from the logical block types.
1778	    list_of_pack_patterns = alloc_and_load_pack_patterns(logical_block_types);
1779	    // Use the pack patterns to allocate and load the pack molecules.
1780	    std::multimap<AtomBlockId, PackMoleculeId> atom_molecules_multimap;
1781	    expected_lowest_cost_pb_gnode.resize(atom_nlist.blocks().size(), nullptr);
1782	    alloc_and_load_pack_molecules(atom_molecules_multimap,
1783	                                  atom_nlist,
1784	                                  models,
1785	                                  logical_block_types);
1786	
1787	    // The multimap is a legacy thing. Since blocks can be part of multiple pack
1788	    // patterns, during prepacking a block may be contained within multiple
1789	    // molecules. However, by the end of prepacking, molecules should be
1790	    // combined such that each block is contained in one and only one molecule.
1791	    atom_molecule_.resize(atom_nlist.blocks().size(), PackMoleculeId::INVALID());
1792	    for (AtomBlockId blk_id : atom_nlist.blocks()) {
1793	        // Every atom block should be packed into a single molecule (no more
1794	        // or less).
1795	        VTR_ASSERT(atom_molecules_multimap.count(blk_id) == 1);
1796	        atom_molecule_[blk_id] = atom_molecules_multimap.find(blk_id)->second;
1797	    }
1798	}
