1800	// TODO: Since this is constant per molecule, it may make sense to precompute
1801	//       this information and store it in the prepacker class. This may be
1802	//       expensive to calculate for large molecules.
1803	t_molecule_stats Prepacker::calc_molecule_stats(PackMoleculeId molecule_id,
1804	                                                const AtomNetlist& atom_nlist,
1805	                                                const LogicalModels& models) const {
1806	    VTR_ASSERT(molecule_id.is_valid());
1807	    t_molecule_stats molecule_stats;
1808	
1809	    const t_pack_molecule& molecule = pack_molecules_[molecule_id];
1810	
1811	    //Calculate the number of available pins on primitives within the molecule
1812	    for (auto blk : molecule.atom_block_ids) {
1813	        if (!blk) continue;
1814	
1815	        ++molecule_stats.num_blocks; //Record number of valid blocks in molecule
1816	
1817	        LogicalModelId model_id = atom_nlist.block_model(blk);
1818	        const t_model& model = models.get_model(model_id);
1819	
1820	        for (const t_model_ports* input_port = model.inputs; input_port != nullptr; input_port = input_port->next) {
1821	            molecule_stats.num_input_pins += input_port->size;
1822	        }
1823	
1824	        for (const t_model_ports* output_port = model.outputs; output_port != nullptr; output_port = output_port->next) {
1825	            molecule_stats.num_output_pins += output_port->size;
1826	        }
1827	    }
1828	    molecule_stats.num_pins = molecule_stats.num_input_pins + molecule_stats.num_output_pins;
1829	
1830	    //Calculate the number of externally used pins
1831	    std::set<AtomBlockId> molecule_atoms(molecule.atom_block_ids.begin(), molecule.atom_block_ids.end());
1832	    for (auto blk : molecule.atom_block_ids) {
1833	        if (!blk) continue;
1834	
1835	        for (auto pin : atom_nlist.block_pins(blk)) {
1836	            auto net = atom_nlist.pin_net(pin);
1837	
1838	            auto pin_type = atom_nlist.pin_type(pin);
1839	            if (pin_type == PinType::SINK) {
1840	                auto driver_blk = atom_nlist.net_driver_block(net);
1841	
1842	                if (molecule_atoms.count(driver_blk)) {
1843	                    //Pin driven by a block within the molecule
1844	                    //Does not count as an external connection
1845	                } else {
1846	                    //Pin driven by a block outside the molecule
1847	                    ++molecule_stats.num_used_ext_inputs;
1848	                }
1849	
1850	            } else {
1851	                VTR_ASSERT(pin_type == PinType::DRIVER);
1852	
1853	                bool net_leaves_molecule = false;
1854	                for (auto sink_pin : atom_nlist.net_sinks(net)) {
1855	                    auto sink_blk = atom_nlist.pin_block(sink_pin);
1856	
1857	                    if (!molecule_atoms.count(sink_blk)) {
1858	                        //There is at least one sink outside of the current molecule
1859	                        net_leaves_molecule = true;
1860	                        break;
1861	                    }
1862	                }
1863	
1864	                //We assume that any fanout occurs outside of the molecule, hence we only
1865	                //count one used output (even if there are multiple sinks outside the molecule)
1866	                if (net_leaves_molecule) {
1867	                    ++molecule_stats.num_used_ext_outputs;
1868	                }
1869	            }
1870	        }
1871	    }
1872	    molecule_stats.num_used_ext_pins = molecule_stats.num_used_ext_inputs + molecule_stats.num_used_ext_outputs;
1873	
1874	    return molecule_stats;
1875	}
1876	
1877	t_molecule_external_nets Prepacker::calc_molecule_external_nets(
1878	    PackMoleculeId molecule_id,
1879	    const AtomNetlist& atom_nlist) const {
1880	
1881	    VTR_ASSERT(molecule_id.is_valid());
1882	
1883	    t_molecule_external_nets external_nets;
1884	
1885	    const t_pack_molecule& molecule = pack_molecules_[molecule_id];
1886	
1887	    // Set of all atoms in this molecule
1888	    std::unordered_set<AtomBlockId> mol_atoms(
1889	        molecule.atom_block_ids.begin(),
1890	        molecule.atom_block_ids.end());
1891	
1892	    // Returns true if the net has at least one sink outside the molecule.
1893	    auto net_leaves_molecule = [&](AtomNetId net) -> bool {
1894	        if (!net)
1895	            return false;
1896	        for (AtomPinId sink_pin : atom_nlist.net_sinks(net)) {
1897	            AtomBlockId sink_block = atom_nlist.pin_block(sink_pin);
1898	            if (!mol_atoms.count(sink_block))
1899	                return true;
1900	        }
1901	        return false;
1902	    };
1903	
1904	    for (AtomBlockId atom_blk_id : molecule.atom_block_ids) {
1905	        if (!atom_blk_id)
1906	            continue;
1907	
1908	        // Clock pins are sinks; a net is external if its driver is outside the molecule.
1909	        for (AtomPinId pin : atom_nlist.block_clock_pins(atom_blk_id)) {
1910	            AtomNetId net = atom_nlist.pin_net(pin);
1911	            if (!net)
1912	                continue;
1913	            AtomBlockId driver_block = atom_nlist.net_driver_block(net);
1914	            if (!driver_block)
1915	                continue;
1916	            if (!mol_atoms.count(driver_block))
1917	                external_nets.ext_clock_nets.insert(net);
1918	        }
1919	
1920	        // Input pins are sinks; a net is external if its driver is outside the molecule.
1921	        for (AtomPinId pin : atom_nlist.block_input_pins(atom_blk_id)) {
1922	            AtomNetId net = atom_nlist.pin_net(pin);
1923	            if (!net)
1924	                continue;
1925	            AtomBlockId driver_block = atom_nlist.net_driver_block(net);
1926	            if (!driver_block)
1927	                continue;
1928	            if (!mol_atoms.count(driver_block))
1929	                external_nets.ext_input_nets.insert(net);
1930	        }
1931	
1932	        // Output pins are drivers; a net is external if any of its sinks are outside the molecule.
1933	        for (AtomPinId pin : atom_nlist.block_output_pins(atom_blk_id)) {
1934	            AtomNetId net = atom_nlist.pin_net(pin);
1935	            if (!net)
1936	                continue;
1937	            if (net_leaves_molecule(net))
1938	                external_nets.ext_output_nets.insert(net);
1939	        }
1940	    }
1941	
1942	    return external_nets;
1943	}
1944	
1945	t_molecule_stats Prepacker::calc_max_molecule_stats(const AtomNetlist& atom_nlist, const LogicalModels& models) const {
1946	    t_molecule_stats max_molecules_stats;
1947	    for (PackMoleculeId molecule_id : molecules()) {
1948	        //Calculate per-molecule statistics
1949	        t_molecule_stats cur_molecule_stats = calc_molecule_stats(molecule_id, atom_nlist, models);
1950	
1951	        //Record the maximums (member-wise) over all molecules
1952	        max_molecules_stats.num_blocks = std::max(max_molecules_stats.num_blocks, cur_molecule_stats.num_blocks);
1953	
1954	        max_molecules_stats.num_pins = std::max(max_molecules_stats.num_pins, cur_molecule_stats.num_pins);
1955	        max_molecules_stats.num_input_pins = std::max(max_molecules_stats.num_input_pins, cur_molecule_stats.num_input_pins);
1956	        max_molecules_stats.num_output_pins = std::max(max_molecules_stats.num_output_pins, cur_molecule_stats.num_output_pins);
1957	
1958	        max_molecules_stats.num_used_ext_pins = std::max(max_molecules_stats.num_used_ext_pins, cur_molecule_stats.num_used_ext_pins);
1959	        max_molecules_stats.num_used_ext_inputs = std::max(max_molecules_stats.num_used_ext_inputs, cur_molecule_stats.num_used_ext_inputs);
1960	        max_molecules_stats.num_used_ext_outputs = std::max(max_molecules_stats.num_used_ext_outputs, cur_molecule_stats.num_used_ext_outputs);
1961	    }
1962	
1963	    return max_molecules_stats;
1964	}
1965	
1966	Prepacker::~Prepacker() {
1967	    // When the prepacker is reset (or destroyed), clean up the internal data
1968	    // members.
1969	    free_list_of_pack_patterns(list_of_pack_patterns);
1970	}
